  t1->s2 = t2->s2;
  t1->s3 = t2->s3;
  t1->s4 = t2->s4;
  t1->s5 = t2->s5;
  t1->s6 = t2->s6;
  t1->s7 = t2->s7;
  t1->s8 = t2->s8;
  t1->s9 = t2->s9;
  t1->s10 = t2->s10;
  t1->s11 = t2->s11;
}

static void copy_trapframe(struct trapframe *f1, struct trapframe *f2) {
  f1->kernel_satp = f2->kernel_satp;
  f1->kernel_sp = f2->kernel_sp;
  f1->kernel_trap = f2->kernel_trap;
  f1->epc = f2->epc;
  f1->kernel_hartid = f2->kernel_hartid;
  f1->ra = f2->ra;
  f1->sp = f2->sp;
  f1->gp = f2->gp;
  f1->tp = f2->tp;
  f1->t0 = f2->t0;
  f1->t1 = f2->t1;
  f1->t2 = f2->t2;
  f1->s0 = f2->s0;
  f1->s1 = f2->s1;
  f1->a0 = f2->a0;
  f1->a1 = f2->a1;
  f1->a2 = f2->a2;
  f1->a3 = f2->a3;
  f1->a4 = f2->a4;
  f1->a5 = f2->a5;
  f1->a6 = f2->a6;
  f1->a7 = f2->a7;
  f1->s2 = f2->s2;
