int mappages(pagetable_t pagetable, uint64_t va, uint64_t size, uint64_t pa, int perm)
{
    uint64_t a, last;

    pte_t *pte;
    //printf("mappages: %d\n", va);
    if(size == 0)
        panic("mappages: size");

    a = PGROUNDDOWN(va);
    last = PGROUNDDOWN(va + size - 1);
    for(;;){
        if((pte = walk(pagetable, a, 1)) == 0)
            panic("walk return -1\n");
        if(*pte & PTE_V) {
            printf("mappages: %p\n", va);
            //exit(0);
            panic("mappages: remap");
        }
        *pte = PA2PTE(pa) | perm | PTE_V;
        *pte = PA2PTE(pa) | perm | PTE_V;
        *pte = PA2PTE(pa) | perm | PTE_V;
        //printf("mappages: %p %p %p %p %p %p %p\n", perm, perm & PTE_R,  perm & PTE_W, perm & PTE_X,  perm & PTE_U, *pte, pte);
        //printf("mappages: %p %p\n", a, pa);
        if(a == last)
            break;
        //if(a < 0x80000000)
            //printf("mappages: va: %p pa: %p\n", a, pa);
        a += PGSIZE;
        //printf("mappages: %p\n", pa);
        pa += PGSIZE;
    }
    return 0;
}

#define PTE_FLAGS(pte) ((pte) & 0x3FF)
void uvmunmap(pagetable_t pagetable, uint64_t va, uint64_t npages, int do_free){
    uint64_t a;
    pte_t *pte;
    if((va % PGSIZE) != 0){
        panic("uvmunmap : not aligned");
    }
    //printf("uvmunmap: %p\n", va);
    for(a = va; a < va + npages * PGSIZE; a += PGSIZE){
        if ((pte = walk(pagetable, a, 0)) == 0) {
            continue;
            panic("vmunmap: walk");
        }

        if ((*pte & PTE_V) == 0) {
            //printf("uvmunmap: %p %p %p\n", a, pte, *pte);
            continue;
        }

        if (PTE_FLAGS(*pte) == PTE_V)
            panic("vmunmap: not a leaf");
        if(do_free){
            uint64_t pa = PTE2PA(*pte);
            kfree((void*)pa);
        }
        *pte = 0;
    }
} 

