struct {
    struct spinlock lock;
    struct run *freelist;
    uint64_t npage;
} kmem;

void kfree(void *pa){
    struct run *r;
    if(((uint64_t)pa % PGSIZE) != 0){
        panic("kfree: pa not aliend");
    }
    if((char *)pa < end) {
        panic("kfree: pa less than end");
    }
    if((uint64_t)pa >= PHYSTOP) {

        panic("kfree: pa bigger than phymax");
    }
    memset(pa, 1, PGSIZE);
    //printf("kfree: %p\n", pa);
    r = (struct run*)pa;

    acquire(&kmem.lock);
    r->next = kmem.freelist;
    kmem.freelist = r;
    kmem.npage++;
    release(&kmem.lock);
}

void kinit(){
