	page->flags = 0;
}

static inline uint32_t _align_page(uint32_t address) {
	//eg: address = 0x8000_0001, the aligned address will be
	//0x8000_1000; address = 0x8000_0fff, the aligned address wiil
	//be 0x8000_1000
	uint32_t order = (1 << PAGE_ORDER) - 1;	 
	return (address + order) & (~order);
}


static inline int _is_free(struct Page *page) {
	if (page->flags & PAGE_TAKEN) {
		return 0;
	} else {
		return 1;
	}
}

static inline void _set_flag(struct Page* page, uint8_t flags) {
	page->flags |= flags;
}

static inline int _is_last(struct Page* page) {
	if (page->flags & PAGE_LAST) {
		return 1;
	} else {
		return 0;
	}
}


void page_init(void) {
	/*
	 * We reserved 8 Pages (8 * 4096) to hold the Page Structures.
	 * It should be enought to manage at most 128 MB (8 * 4096 * 4096)
	 */
	_num_pages = (HEAP_SIZE / PAGE_SIZE) - 8;
	printf("HEAP_START = %x, HEAP_SIZE = %x, num of pages = %d\n", HEAP_START, HEAP_SIZE, _num_pages);

	//the first 8 pages used to store whether the pages left is allocated
	struct Page *page = (struct Page *)HEAP_START;
	for (int i=0; i<_num_pages; i++) {
		_clear(page);
		page++;
	}

	_alloc_start = _align_page(HEAP_START + 8 * PAGE_SIZE);
	_alloc_end = _alloc_start + (PAGE_SIZE * _num_pages);	

	printf("TEXT: 0x%x -> 0x%x\n", TEXT_START, TEXT_END);
	printf("RODATA: 0x%x -> 0x%x\n", RODATA_START, RODATA_END);
	printf("DATA: 0x%x -> 0x%x\n", DATA_START, DATA_END);
	printf("BSS: 0x%x -> 0x%x\n", BSS_START, BSS_END);
	printf("HEAP: 0x%x -> 0x%x\n", _alloc_start, _alloc_end);
}


/*
 * Allocate a memory block which is composed of contiguous physical pages
 * - npages: the number of PAGE_SIZE pages to allocate
 */

void* page_alloc(int npages) {
	int found = 0;

	struct Page* page_i = (struct Page*)HEAP_START;

	for (int i=0; i<=(_num_pages - npages); i++) {
		if (_is_free(page_i)) {
			found = 1;
			/* 
			 * meet a free page, continue to check if following
			 * (npages - 1) pages are also unallocked.
			 */
			struct Page *page_j = page_i;	//here check two of the same address
			for (int j=i; j<(i+npages); j++) {
				if (!_is_free(page_j)) {
					found = 0;
					break;
				}
				page_j++;
			}

			/*
			 * get a memory block which is good enough for us,
			 * take housekeeping, then return the actual start
			 * addree of the first page of this memory block
			 */
			if (found) {	
				struct Page *page_k = page_i;
				for (int k=i; k<(i+npages); k++) {
					_set_flag(page_k, PAGE_TAKEN);
					page_k++;
				}
				page_k--;
				_set_flag(page_k, PAGE_LAST);
				return (void*)(_alloc_start+i*PAGE_SIZE);
			}
		}
		page_i++;
	}	
	return NULL;
}

void page_free(void *p) {
	/*
	 * Assert (TBD) if p is invalid
	 */
	if (!p || (uint32_t)p >= _alloc_end) {
		return;
	}

	/* get the first page descriptor of this memory block */
	struct Page* page = (struct Page*)HEAP_START;
	page += ((uint32_t)p - _alloc_start) / PAGE_SIZE;

	/* loop and clear all the page desciptors of the memory block */
	while( !_is_free(page) ) {
		if (_is_last(page)) {
			_clear(page);
			break;
		} else {
			_clear(page);
			page++;
		}
	}
}

