uint64_t sys_shmget(void) {
    int key;
    uint64_t size;
    int shmflg;
    argint(0, &key);
    argaddr(1, &size);
    argint(2, &shmflg);
    //printf("sys_shmget: %d %d %d\n", key, size, shmflg);
    //while(1);
    uint64_t start = 0;
    shm.shm_length[shm_id] = size;
    shm.addr[shm_id] = myproc()->sz + PGSIZE + start;
    //printf("shmaddr: %p\n", shm.addr[shm_id]);
    shm.pid[shm_id] = myproc()->pid;
    myproc()->sz += size;
    return shm_id++;
}

uint64_t sys_shmat(void) {
    int id;
    uint64_t addr;
    int shmflg;
    argint(0, &id);
    argaddr(1, &addr);
    argint(2, &shmflg);
    //printf("sys_shmat\n");
    for(int i = 0; i < shm.shm_length[id] / PGSIZE ; i++) {
        char *mem = (char *)kalloc();
        shm.pa[id][i] = (uint64_t)mem;
        //printf("vaddr: %p %p\n", shm.addr[id] + i * PGSIZE, mem);
        mappages(myproc()->pagetable, shm.addr[id] + i * PGSIZE, PGSIZE, mem, PTE_R | PTE_U | PTE_V | PTE_W | PTE_X);
    }
    //printf("sys_shmat: %d %d %d %d %p %p\n", myproc()->pid, id, addr, shmflg);
    return shm.addr[id];
}

uint64_t sys_shmctl(void) {
    int id;
    uint64_t cmd;
    uint64_t addr;
    argint(0, &id);
    argaddr(1, &cmd);
    argaddr(2, &addr);
    //printf("sys_shmctl: %d %d %d %p\n", myproc()->pid, id, addr, cmd);
    return 0;
}

