uint64_t sys_times(void){
    struct tms{                     
    	long tms_utime;  
    	long tms_stime;  
    	long tms_cutime; 
    	long tms_cstime; 
    } tms;
    tms.tms_utime = user_ticks * (int)(1e3);
    tms.tms_stime = super_ticks * (int)(1e3);
    tms.tms_cutime = c_user_ticks * (int)(1e3);
    tms.tms_cutime = (tms.tms_cutime == 0) ? 1 : tms.tms_cutime;
    tms.tms_cstime = c_super_ticks * (int)(1e3);
    uint64_t addr;
    argaddr(0, &addr);
    copyout(myproc()->pagetable ,addr, (char *)&tms, sizeof(tms));
    return 0;
}

