uint64_t sys_sbrk(void) {
  uint64_t addr;
  uint64_t n;
  argaddr(0, &n);
  //trapframedump(myproc()->trapframe);
  addr = myproc()->sz;
  //printf("sbrk param n: %p %p\n", n, addr);
  if(n == 0){
    return (uint64_t)addr;    
  }
  if(n < addr) {
    return addr;
  }
  if (growproc(n - addr) < 0)
    return -1;
  return (uint64_t)myproc()->sz;;
}

uint64_t sys_sleep(void){
    int n;
    uint32_t ticks0;

    argaddr(0, &n);
    //printf("sys_sleep : %d %d\n", n, myproc()->pid);
    acquire(&tickslock);
    ticks0 = user_ticks + super_ticks;
    while((user_ticks + super_ticks - ticks0) * 10000 < n){
        //printf("sys_sleep %0x %0x\n", (user_ticks + super_ticks - ticks0) * 100, n);
        if(killed(myproc())){
            release(&tickslock);
            return -1;
        }
        sleep(&super_ticks, &tickslock);
    }
    release(&tickslock);
    //printf("sys_sleep end\n");
    return 0;
}

