    // }

    for (int i = 0; i < nfds && urfds; i++) {
      if (!test_bit(i, &rfds)) {
        continue;
      }
      struct file *f = p->ofile[i];
      //printf("enter read: fd %d, ftype :%d\n", i, f->type);
      switch (f->type) {
      case FD_PIPE:
        if (!f->readable /*|| pipe_empty(f->pipe)*/) {
          clear_bit(i, &rfds);
          break;
        }
        // printf("arrive here!\n");
      case FD_DEVICE:
      /*
