      case FD_SOCK:
        if (do_lwip_select(f->socketnum, (struct timeval *)&timeout) > 0) {
          ret++;
        }
        */
        break;

      default:
        break;
      }
    }

    for (int i = 0; i < nfds && uwfds; i++) {
      if (!test_bit(i, &wfds)) {
        continue;
      }
      // printf("enter write: fd %d\n", i);
      struct file *f = p->ofile[i];
      switch (f->type) {
      case FD_PIPE:
        if (!f->writable /*|| pipe_full(f->pipe)*/) {
          clear_bit(i, &wfds);
          break;
        }
      case FD_DEVICE:
      /*
