        if (do_lwip_select(f->socketnum, (struct timeval *)&timeout) > 0) {
          ret++;
        }
        */
        break;

      default:
        break;
      }
    }

    if (ret) {
      break;
    }

    if (expire == -1) {
      break;
    } else {
      if (r_time() - start_time >= expire) {
        break;
      }
    }
  }

  memset((void *)&exfds, 0, sizeof(struct fdset));

  if (urfds)
    either_copyout(1, urfds, (char *)&rfds, sizeof(struct fdset));
