int flags2perm(int flags)
{
    int perm = 0;
    if(flags & 0x1)
      perm = PTE_X;
    if(flags & 0x2)
      perm |= PTE_W;
    if(flags & 0x4)
      perm |= PTE_R;
    return perm;
}

static int loadaux(pagetable_t pagetable, uint64_t sp, uint64_t stackbase, uint64_t *aux) {
    int argc = aux[0];
