    for(int i=1;i<=2*argc+2;i++){
      printf("final raw aux[%d] = %p\n",i,aux[i]);
    }
    */
    sp -= (2 * argc + 2) * sizeof(uint64_t);
    if (sp < stackbase) {
      return -1;
    }
    aux[0] = 0;
    if (copyout(pagetable, sp, (char *)(aux + 1), (2 * argc + 2) * sizeof(uint64_t)) < 0) {
      return -1;
    }
    return sp;
}

