static int loadseg(pagetable_t pagetable, uint64_t va, struct inode *ep, uint32_t offset, uint32_t sz){
    uint32_t i = 0, n;
    uint64_t pa;
    uint64_t va_off = 0;
    if(va % PGSIZE){
        va_off = va % PGSIZE;
        va = va - va_off;
        pa = walkaddr(pagetable, va);
        if(pa == NULL){
            panic("loadseg: address should exist");
        }
        n = PGSIZE - va_off;
        if(readi(ep, 0, (uint64_t)(pa + va_off), offset, n) != n){
            printf("loadseg: read error\n");
        }
        i += n; 
        va += PGSIZE;
    }
    for(; i < sz; ){
        pa = walkaddr(pagetable, va);
        if(pa == NULL){
            panic("loadseg: address should exist 1");
        }
        if(sz - i < PGSIZE){
            n = sz - i;
        } else {
            n = PGSIZE;
        }
        if(readi(ep, 0, (uint64_t)pa, offset + i, n) != n){
            return -1;
        }
        i += n;
        va += PGSIZE;
    }
    return 0;
}

static int readelfhdr(struct inode *ep, struct elfh *elf){
    if(readi(ep, 0, (uint64_t)elf, 0, sizeof(struct elfh)) != sizeof(struct elfh)){
        return -1;
    }
    if(elf->magic != ELF_MAGIC){
        return -1;
    }
    return 0;
}

uint64_t loadelf(struct elfh *elf, struct inode *ep, struct proghdr *phdr, pagetable_t pagetable, uint64_t *sz, int *is_dynamic){
    uint64_t sz1;
    int i, off;
    struct proghdr ph;
    int getphdr = 0;
    for(i = 0, off = elf->phoff; i < elf->phnum; i++, off += sizeof(struct proghdr)){
        if(readi(ep, 0, (uint64_t)&ph, off, sizeof(struct proghdr)) != sizeof(struct proghdr)){
            printf("readi failed\n");
            return -1;
        }
        if(ph.type == ELF_PROG_LOAD){
            if (ph.memsz < ph.filesz) {
                printf("ph.memsz < ph.filesz\n");
                return -1;
            }
            if (ph.vaddr + ph.memsz < ph.vaddr) {
                printf("ph.vaddr + ph.memsz < ph.vaddr\n");
                return -1;
            }
            if (!getphdr && phdr && ph.off == 0) {
                phdr->vaddr = elf->phoff + ph.vaddr;
            }
            int perm = 0;
            if (ph.flags & ELF_PROG_FLAG_EXEC)
                perm |= PTE_X;
            if (ph.flags & ELF_PROG_FLAG_WRITE)
                perm |= PTE_W;
            if (ph.flags & ELF_PROG_FLAG_READ)
                perm |= PTE_R;
            if((sz1 = uvmalloc(pagetable, *sz, PGROUNDUP(ph.vaddr + ph.memsz), perm)) == 0){
                printf("uvmalloc failed\n");
                return -1;
            }
            *sz = sz1;
            if(loadseg(pagetable, ph.vaddr, ep, ph.off, ph.filesz) < 0){
                printf("loadseg failed\n");
                return -1;
            } else if (ph.type == ELF_PROG_PHDR) {
                if (phdr) {
                    getphdr = 1;
                    *phdr = ph;
                }
            } else if (ph.type == ELF_PROG_INTERP) {
                *is_dynamic = 1;
            } else {
              // printf("ph.type: %d ph.type != ELF_PROG_LOAD\n", ph.type);
            }
        }
    }
    return 0;
}

uint64_t get_total_mapping_size(struct elfh *interp_elf_ex, struct inode *interpreter) {
    uint64_t min_addr = -1;
    uint64_t max_addr = 0;
    int is_true = 0;
    struct proghdr ph;
    for (uint32_t i = 0, off = interp_elf_ex->phoff; i < interp_elf_ex->phnum; i++, off += sizeof(struct proghdr)) {
        if (readi(interpreter, 0, (uint64_t)&ph, off, sizeof(struct proghdr)) != sizeof(struct proghdr)) {
            debug_print("[get_total_mapping_size]eread failed\n");
            return -1;
        }
        if (ph.type == ELF_PROG_LOAD) {
            min_addr = min(min_addr, PGROUNDDOWN(ph.vaddr));
            max_addr = max(max_addr, ph.vaddr + ph.memsz);
            is_true = 1;
        }
    }
    return is_true ? (max_addr - min_addr) : 0;
}

