#define PIPESIZE 512

struct pipe {
    struct spinlock lock;
    char data[PIPESIZE];
    uint32_t nread;
    uint32_t nwrite;
    int readopen;
    int writeopen;
};

int pipealloc(struct file **f0, struct file **f1){
    struct pipe *pi;

    pi = 0;
    *f0 = *f1 = 0;

    if( !(*f0 = filealloc()) || !(*f1 = filealloc()) || !(pi = (struct pipe *)kalloc())){
        if(pi)
            kfree((char*)pi);
        if(*f0)
            fileclose(*f0);
        if(*f1)
            fileclose(*f1);
        return -1;
    }
    pi->readopen = 1;
    pi->writeopen = 1;
    pi->nwrite = 0;
    pi->nread = 0;
    initlock(&pi->lock, "pipe");
    (*f0)->type = FD_PIPE;
    (*f0)->readable = 1;
    (*f0)->writable = 0;
    (*f0)->pipe = pi;

    (*f1)->type = FD_PIPE;
    (*f1)->readable = 0;
    (*f1)->writable = 1;
    (*f1)->pipe = pi;
    return 0;
}

void pipeclose(struct pipe *pi, int writable){
    acquire(&pi->lock);
    if(writable){
        pi->writeopen = 0;
        wakeup(&pi->nread);
    } else {
        pi->readopen = 0;
        wakeup(&pi->nwrite);
    }
    if(pi->readopen == 0 && pi->writeopen == 0){
        release(&pi->lock);
        kfree((char *) pi);
    } else {
        release(&pi->lock);
    }
}

int pipewrite(struct pipe *pi, uint64_t addr, int n){
    int i = 0;
    struct proc *p = myproc();

    acquire(&pi->lock);
    while(i < n){
        if(pi->readopen == 0 || killed(p)){
            release(&pi->lock);
            return -1;
        }
        if(pi->nwrite == pi->nread + PIPESIZE){
            wakeup(&pi->nread);
            sleep(&pi->nwrite, &pi->lock);
        } else {
            char ch;
            if(copyin(p->pagetable, &ch, addr + i, 1) == -1){
                break;
            }
            pi->data[pi->nwrite ++ % PIPESIZE] = ch;
            i++;
        }
    }
    wakeup(&pi->nread);
    release(&pi->lock);

    return i;
}

