static struct buf* bget(uint32_t dev, uint32_t sect){
    struct buf *b;
    acquire(&bcache.lock);

    /* find */
    for(b = bcache.head.next; b != &bcache.head; b = b->next){
        if(b->dev == dev && b->sectorno == sect){
            b->refcnt ++;
            release(&bcache.lock);
            acquiresleep(&b->lock);
            return b;
        }
    }
    /* unfind */
    for(b = bcache.head.prev; b != &bcache.head; b = b->prev){
        if(! b->refcnt){
            b->dev = dev;
            b->sectorno = sect;
            b->valid = 0;
            b->refcnt = 1;
            release(&bcache.lock);
            acquiresleep(&b->lock);
            return b;
        }
    }
    //panic("bget: no buffers");
}

