    struct buf *b;

    b = bget(dev, sect);
    if(! b->valid){
        virtio_disk_rw(b, 0);
        b->valid = 1;
    }
    return b;
}

// write the disk from the buffer in mem to disk
void bwrite(struct buf *b){
    /*
    if(!holdingsleep(&b->lock)){
        panic("bwrite");
    }
    */
    virtio_disk_rw(b, 1);
}

void brelse(struct buf *b){
    if(!holdingsleep(&b->lock)){
        panic("brelse");
    }
    releasesleep(&b->lock);

    acquire(&bcache.lock);

    b->refcnt --;

    /* LRU : if the buffer's refcnt equal zero, put it behind head*/
    if(b->refcnt == 0){
        b->next->prev = b->prev;
        b->prev->next = b->next;
        //printf("brelse start: %x\n", b);
        b->next = bcache.head.next;
        b->prev = &bcache.head;
        bcache.head.next->prev = b;
        bcache.head.next = b;
    }

    release(&bcache.lock);
}

void bpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt++;
    release(&bcache.lock);
}

void bunpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt--;
    release(&bcache.lock);
}

