void initlock(struct spinlock *lock, char *name){
    lock->name = name;
    lock->locked = 0;
    lock->cpu = 0; // default 0 hart
}

// 获取锁
void acquire(struct spinlock *lock){

    push_off(); // 一定要先关中断

    if(holding(lock)){
        panic("已经持有锁"); // 顺序错误
    }

    while(__sync_lock_test_and_set(&lock->locked, 1) != 0){

    }

    __sync_synchronize();

    lock->cpu = mycpu();
}

void release(struct spinlock *lock){
    if(!holding(lock)){
        panic("release");
    }

    lock->cpu = 0;

    __sync_synchronize();

    __sync_lock_release(&lock->locked);

    pop_off();
}

void push_off(void){
    int old = intr_get();     //是否有中断

    intr_off();

    if(mycpu()->noff == 0){
        mycpu()->intena = old;
    }
    mycpu()->noff += 1;     //调用一次就加1
}

void pop_off(void)
{
  struct cpu *c = mycpu();
  if(intr_get())
    panic("pop_off - interruptible");
  if(c->noff < 1)
    panic("pop_off");
  c->noff -= 1;
  if(c->noff == 0 && c->intena)
    intr_on();
}

int holding(struct spinlock *lock)
{
  int r;
  r = (lock->locked && lock->cpu == mycpu());
  return r;
}

